SELECT * FROM (
    SELECT inner_q.*, ROWNUM rnum FROM (
        SELECT

        FROM alarm a

        WHERE a.user_code = #{userCode}
            AND a.check_yn = 'Y'
            AND a.check_yn = 'N'
        ORDER BY a.alarm_date DESC, a.alarm_id DESC
    ) inner_q
    WHERE ROWNUM  <=  (#{offset} + #{pageSize})
)
WHERE rnum  >  #{offset}

SELECT * FROM (
    SELECT

    FROM alarm a

    WHERE a.user_code = #{userCode}
    ORDER BY a.alarm_date DESC, a.alarm_id DESC
)
WHERE ROWNUM  <=  #{limit}

SELECT

FROM alarm a

WHERE a.alarm_id = #{alarmId}
	AND a.user_code = #{userCode}

mapper.update:
UPDATE alarm
   SET check_yn  = CASE WHEN check_yn = 'Y' THEN 'N' ELSE 'Y' END,
       alarm_chk = CASE WHEN check_yn = 'Y' THEN NULL ELSE SYSDATE + 9/24 END
 WHERE alarm_id = #{alarmId}
   AND user_code = #{userCode}

UPDATE alarm
   SET check_yn = 'Y',
       alarm_chk = SYSDATE + 9/24
 WHERE alarm_id = #{alarmId}
   AND user_code = #{userCode}
   AND check_yn = 'N'
